+  get OptionsClass(): new () => LinkStyleOptions {
+    return LinkStyleOptions;
+  }
+
+  apply(text: string, options: LinkStyleOptions): string {
+    if (options.linkStyle === 'markdown' || options.imageStyle === 'markdown') {
+      text = this.convertWikiToMarkdown(text, options);
+    }
+
+    if (options.linkStyle === 'wiki' || options.imageStyle === 'wiki') {
+      text = this.convertMarkdownToWiki(text, options);
+    }
+
+    return text;
+  }
+
+  private convertWikiToMarkdown(text: string, options: LinkStyleOptions): string {
+    return text.replace(/(!?)\\[\\[([^\\]\
|]+)(?:\\|([^\\]\
|]*))?\\]\\]/gu, (match, embed: string, target: string, display: string | undefined) => {
+      if ((embed === '!' && options.imageStyle !== 'markdown') || (embed !== '!' && options.linkStyle !== 'markdown')) {
+        return match;
+      }
+
+      const defaultDisplay = this.defaultHeadingDisplay(target);
+      if (embed === '!') {
+        const alt = display === undefined || display === '' || display === '300' || /^300x200$/u.test(display) ? target : display;
+        return `![${alt}](${target})`;
+      }
+
+      return `[${display === undefined || display === '' ? defaultDisplay : display}](${target})`;
+    });
+  }
+
+  private convertMarkdownToWiki(text: string, options: LinkStyleOptions): string {
+    let result = '';
+    let index = 0;
+
+    while (index < text.length) {
+      const parsed = this.parseInlineLink(text, index);
+      if (!parsed) {
+        result += text[index++];
+        continue;
+      }
+
+      const style = parsed.isImage ? options.imageStyle : options.linkStyle;
+      if (style !== 'wiki' || parsed.target.includes('://')) {
+        result += parsed.source;
+      } else if (parsed.isImage) {
+        const display = parsed.label === '' || parsed.label === parsed.target ? '' : `|${parsed.label}`;
+        result += `![[${parsed.target}${display}]]`;
+      } else {
+        const defaultDisplay = this.defaultHeadingDisplay(parsed.target);
+        const display = parsed.label === parsed.target || parsed.label === defaultDisplay ? '' : `|${parsed.label}`;
+        result += `[[${parsed.target}${display}]]`;
+      }
+
+      index = parsed.endIndex;
+    }
+
+    return result;
+  }
+
+  private parseInlineLink(text: string, startIndex: number): {source: string, endIndex: number, isImage: boolean, label: string, target: string} | null {
+    const isImage = text[startIndex] === '!';
+    const labelStart = isImage ? startIndex + 1 : startIndex;
+    if (text[labelStart] !== '[') {
+      return null;
+    }
+
+    let index = labelStart + 1;
+    let depth = 1;
+    while (index < text.length && depth > 0) {
+      if (text[index] === '\\\') {
+        index += 2;
+      } else if (text[index] === '[') {
+        depth++;
+        index++;
+      } else if (text[index] === ']') {
+        depth--;
+        index++;
+      } else if (text[index++] === '\
') {
+        return null;
+      }
+    }
+
+    if (depth !== 0 || text[index] !== '(') {
+      return null;
+    }
+
+    const label = text.substring(labelStart + 1, index - 1);
+    const destinationStart = ++index;
+    depth = 1;
+    while (index < text.length && depth > 0) {
+      if (text[index] === '\\\') {
+        index += 2;
+      } else if (text[index] === '(') {
+        depth++;
+        index++;
+      } else if (text[index] === ')') {
+        depth--;
+        index++;
+      } else if (text[index++] === '\
') {
+        return null;
+      }
+    }
+
+    if (depth !== 0) {
+      return null;
+    }
+
+    const destination = text.substring(destinationStart, index - 1);
+    const target = this.parseDestination(destination);
+    if (target === null) {
+      return null;
+    }
+
+    return {
+      source: text.substring(startIndex, index),
+      endIndex: index,
+      isImage,
+      label: this.unescapeMarkdown(label),
+      target,
+    };
+  }
+
+  private parseDestination(destination: string): string | null {
+    const trimmed = destination.trim();
+    if (trimmed.startsWith('<')) {
+      let closingIndex = -1;
+      for (let index = 1; index < trimmed.length; index++) {
+        if (trimmed[index] === '\\\') {
+          index++;
+        } else if (trimmed[index] === '>') {
+          closingIndex = index;
+          break;
+        }
+      }
+
+      if (closingIndex === -1 || trimmed.substring(closingIndex + 1).trim() !== '') {
+        return null;
+      }
+      return this.unescapeMarkdown(trimmed.substring(1, closingIndex));
+    }
+
+    if (destination !== trimmed || this.hasUnescapedWhitespace(trimmed)) {
+      return null;
+    }
+    return this.unescapeMarkdown(trimmed);
+  }
+
+  private hasUnescapedWhitespace(text: string): boolean {
+    for (let index = 0; index < text.length; index++) {
+      if (text[index] === '\\\') {
+        index++;
+      } else if (/\\s/u.test(text[index])) {
+        return true;
+      }
+    }
+    return false;
+  }
+
+  private unescapeMarkdown(text: string): string {
+    return text.replace(/\\\\(.)/gu, '$1');
+  }
+
+  private defaultHeadingDisplay(target: string): string {
+    const headingIndex = target.indexOf('#');
+    if (headingIndex === -1) {
+      return target;
+    }
+
+    const page = target.substring(0, headingIndex);
+    const heading = target.substring(headingIndex + 1);
+    return page === '' ? heading : `${page} > ${heading}`;
+  }
